\section{Comparison with étale cohomology}

Let $X$ be a scheme. Since an étale map is also weakly étale by \ref{lemma:etale-weakly-etale} we may
define:

\begin{definition}
    We denote by $\nu = \nu_X$ the morphism of sites $\proet{X} \to \et{X}$ induced by the functor
    from $\et{X}$ to $\proet{X}$ given by $(U \to X) \mapsto (U \to X)$.
    \uses{lemma:etale-weakly-etale, def:proetale-site}
    \label{def:forget-proet}
\end{definition}

\begin{lemma}
    The morphism of sites $\nu$ is continuous.
    \uses{def:forget-proet}
    \label{lemma:forget-proet-continuous}
\end{lemma}

\begin{proof}
    This follows from the definitions, because every étale covering is
    a quasi-compact covering by \ref{lemma:qc-cover-of-flat-fp}.
    \uses{lemma:qc-cover-of-flat-fp}
\end{proof}

We denote by $\nu_{p}\colon \preshv{\proet{X}} \to \preshv{\et{X}}$
and $\nu^{p}\colon \preshv{\et{X}} \to \preshv{\proet{X}}$ the pushforward and pullback functors
on the level of presheafs.

\begin{lemma}
    Let $F$ be a presheaf on $\et{X}$. Then $(\nu^p F)|_{\affproet{X}}$ preserves
    filtered colimits.
    \label{lemma:affproet-pushforward-presheaf-filtered-colim}
\end{lemma}

\begin{proof}
    Let $U = \lim_{\lambda} U_{\lambda}$ be a cofiltered limit. By definition
    of $\affproet{X}$ and because pro-pro-étale is pro-étale, we may assume that the $U_{\lambda}$
    are étale over $X$. Then
    \[
        (\nu^p F)|_{\affproet{X}}(\lim U_{\lambda})
        = \colim_{\mu} F(V_{\mu})
    ,\] where the $V_{\mu}$ run over factorisations
    $U = \lim U_{\lambda} \to V_{\mu} \to X$
    where $V_{\mu} \to X$ is étale. Since the $U_{\lambda}$ are
    locally of finite presentation over $X$, they are finitely presented
    in the categorical sense. Hence, for every such factorisation there
    exists a $\lambda$ such that $U = \lim U_{\lambda} \to V_{\mu}$ factors
    via $U_{\lambda}$. This shows that the $U_{\lambda}$ lie cofinal
    in all $V_{\mu}$, so we obtain
    \[
    \colim_{\mu} F(V_{\mu}) = \colim_{\lambda} F(U_{\lambda})
    = \colim_{\lambda} (\nu^p F)|_{\affproet{X}}(U_{\lambda})
    .\]
\end{proof}

\begin{lemma}
    The topology on $\affproet{X}$ is generated by relatively pro-representable one-hypercovers

    The topology on $\affproet{X}$ is generated by relatively pro-representable one-hypercovers
    with respect to the inclusion $\affet{X} \to \affproet{X}$.
    \label{lemma:affproet-relatively-pro-prepresentable}
    \uses{def:one-cover-relatively-pro-prepresentable}
\end{lemma}

\begin{proof}
    The topology on $\affproet{X}$ is generated by surjections
    $V \to U$ in $\affproet{X}$ and finite standard Zariski coverings. Both
    of these can be relatively pro-represented.
\end{proof}

Further denote by $\nu_{*} \colon \shv{\proet{X}} \to \shv{\et{X}}$ and
$\nu^* \colon \shv{\et{X}} \to \shv{\proet{X}}$ the corresponding pushforward and pullback functors.
Since $\nu^*$ is exact, we have $R \nu^* = \nu^*$ by abuse of notation and we simply write $\nu^*$ everywhere.
In contrast to \cite{proetale}, we write $R \nu_{*}$ for the derived functor of $\nu_{*}$.

\begin{proposition}
    Let $F$ be a sheaf on $\et{X}$. Then $(\nu^p F)|_{\affproet{X}}$ is a sheaf. In particular,
    $(\nu^*F)|_{\affproet{X}} \cong (\nu^p F)|_{\affproet{X}}$.
    \label{prop:presheaf-pushforward-sheaf-affproet}
\end{proposition}

\begin{proof}
    \uses{lemma:affproet-relatively-pro-prepresentable, prop:sheaf-relatively-representable-generated, lemma:affproet-pushforward-presheaf-filtered-colim}
    By \ref{lemma:affproet-relatively-pro-prepresentable} and
    \ref{lemma:affproet-pushforward-presheaf-filtered-colim}, this follows from
    \ref{prop:sheaf-relatively-representable-generated}. The in particular follows
    because we have a commutative diagram
    \[
    \begin{tikzcd}
        \affet{X} \arrow{r} \arrow{d} & \affproet{X} \arrow{d} \\
        \et{X} \arrow{r} & \proet{X}.
    \end{tikzcd}
    \]
\end{proof}

\begin{corollary}[{\cite[Lemma 5.1.1]{proetale}}]
    Let $F$ be a sheaf on $\et{X}$ and $U = \lim_i U_i$ in $\affproet{X}$. Then
    $\nu^*F(U) = \colim_i F(U_i)$.
    \uses{lemma:forget-proet-continuous, def:affproet}
    \label{lemma:pullback-section-affproet}
\end{corollary}

\begin{proof}
    \uses{prop:presheaf-pushforward-sheaf-affproet}
    By \ref{prop:presheaf-pushforward-sheaf-affproet} we have
    $(\nu^*F)|_{\affproet{X}} \cong (\nu^p F)|_{\affproet{X}}$. The claim now follows
    from \ref{lemma:affproet-pushforward-presheaf-filtered-colim}.
\end{proof}

\begin{corollary}
    For any $F \in \shv{\et{X}}$, the unit $F \to \nu_{*} \nu^{*} F$ is an isomorphism.
    \label{lemma:pullback-unit-iso}
\end{corollary}

\begin{proof}
    \uses{lemma:affet-gen-et, lemma:pullback-section-affproet}
    By \ref{lemma:affet-gen-et}, we may check this on any affine $U$ étale over $X$. Since
    $U = \lim U$, the formula of \ref{lemma:pullback-section-affproet} shows the desired isomorphism.
\end{proof}

\begin{corollary}[{\cite[Lemma 5.1.2, fully faithful part]{proetale}}]
    $\nu^*$ is fully faithful.
    \label{lemma:pullback-fully-faithful}
\end{corollary}

\begin{proof}
    \uses{lemma:pullback-unit-iso}
    Follows formally from \ref{lemma:pullback-unit-iso}.
\end{proof}

\begin{definition}
    A sheaf $F$ in $\shv{\proet{X}}$ is called \emph{classical} if it lies in the essential
    image of $\nu^{*}$.
    \uses{def:forget-proet}
    \label{def:classical-sheaf}
\end{definition}

We can recognize the classical sheafs among all pro-étale sheafs by checking
if they preserve affine filtered colimits:

\begin{corollary}[{\cite[Lemma 5.1.2, essential image part]{proetale}}]
    A sheaf $F$ in $\shv{\proet{X}}$ is classical if and only if for any $U \in \affproet{X}$ with
    presentation $U = \lim U_i$, it holds that $F(U) = \colim F(U_i)$.
    \uses{def:classical-sheaf}
    \label{cor:classical-sheaf-iff-preserves}
\end{corollary}

\begin{proof}
    \uses{lemma:pullback-section-affproet, lemma:affproet-gen-proet}
    The only if part follows directly from \Cref{lemma:pullback-section-affproet}. Conversely, let $F$ be
    in $\shv{\proet{X}}$ and suppose $F$ satisfies the formula in the statement. Then
    $\nu^* \nu_{*} F \to F$ is an isomorphism. Indeed, by \Cref{lemma:affproet-gen-proet}, we may check this
    on sections in $\affproet{X}$. Let $U = \lim U_i$ be in $\affproet{X}$. Then again by
    \Cref{lemma:pullback-section-affproet}
    \[
        \nu^* \nu_{*} F (U) = \colim \nu_{*} F(U_i) = \colim F(U_i) = F(U) \qedhere
    .\]
\end{proof}
